import React, { useState, useEffect } from 'react';
import { Store, Plus, Trash2, CheckCircle, MapPin } from 'lucide-react';

const GestionLocales = () => {
  const [locales, setLocales] = useState([]);
  const [nuevoLocal, setNuevoLocal] = useState({
    nombre: '', provincia: 'Tucumán', ciudad: '', zona: '', direccion: ''
  });

  const ubicacionesData = {
    'Tucumán': {
      'San Miguel de Tucumán': ['Centro', 'Barrio Norte', 'Barrio Sur', 'Villa Luján'],
      'Yerba Buena': ['Casco Viejo', 'San José', 'Av. Perón'],
      'Tafí Viejo': ['Centro', 'Lomas de Tafí']
    },
    'Salta': { 'Salta Capital': ['Centro', 'Tres Cerritos'], 'Cafayate': ['Centro'] }
  };

  useEffect(() => {
    setLocales(JSON.parse(localStorage.getItem('mis-locales') || "[]"));
  }, []);

  const handleCrearLocal = (e) => {
    e.preventDefault();
    const localCompleto = { ...nuevoLocal, id: Date.now().toString() };
    const actualizada = [...locales, localCompleto];
    setLocales(actualizada);
    localStorage.setItem('mis-locales', JSON.stringify(actualizada));
    localStorage.setItem('local-actual', JSON.stringify(localCompleto)); // Auto-selección
    alert("¡Sucursal registrada con éxito!");
    setNuevoLocal({ nombre: '', provincia: 'Tucumán', ciudad: '', zona: '', direccion: '' });
  };

  const seleccionarLocal = (local) => {
    localStorage.setItem('local-actual', JSON.stringify(local));
    window.location.reload(); // Recarga para actualizar el dashboard
  };

  return (
    <div style={{ padding: '30px', maxWidth: '800px', margin: '0 auto' }}>
      <h2 style={{ display: 'flex', alignItems: 'center', gap: '12px', color: '#1e293b', fontSize: '1.8rem' }}>
        <Store color="#e67e22" size={32} /> Mis Sucursales
      </h2>

      <form onSubmit={handleCrearLocal} style={formStyle}>
        <div style={gridForm}>
          <div style={{...inputGroup, gridColumn: 'span 2'}}>
            <label style={labelStyle}>Nombre de la Sucursal</label>
            <input required placeholder="Ej: Supermercado Don Pepe - Suc. Yerba Buena" 
              value={nuevoLocal.nombre} onChange={e => setNuevoLocal({...nuevoLocal, nombre: e.target.value})} style={inputStyle} />
          </div>
          <div style={inputGroup}>
            <label style={labelStyle}>Ciudad</label>
            <select required value={nuevoLocal.ciudad} onChange={e => setNuevoLocal({...nuevoLocal, ciudad: e.target.value, zona: ''})} style={inputStyle}>
              <option value="">Seleccionar...</option>
              {Object.keys(ubicacionesData[nuevoLocal.provincia]).map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
          <div style={inputGroup}>
            <label style={labelStyle}>Barrio / Zona</label>
            <select required value={nuevoLocal.zona} onChange={e => setNuevoLocal({...nuevoLocal, zona: e.target.value})} style={inputStyle}>
              <option value="">Seleccionar...</option>
              {(ubicacionesData[nuevoLocal.provincia][nuevoLocal.ciudad] || []).map(z => <option key={z} value={z}>{z}</option>)}
            </select>
          </div>
          <div style={{ ...inputGroup, gridColumn: 'span 2' }}>
            <label style={labelStyle}>Calle y Altura</label>
            <input required placeholder="Ej: Av. Aconquija 1450" value={nuevoLocal.direccion}
              onChange={e => setNuevoLocal({...nuevoLocal, direccion: e.target.value})} style={inputStyle} />
          </div>
        </div>
        <button type="submit" style={btnCrear}><Plus size={20} /> Registrar Sucursal</button>
      </form>

      <div style={listaLocales}>
        {locales.map(l => (
          <div key={l.id} style={cardLocal}>
            <div style={{display: 'flex', gap: '15px', alignItems: 'center'}}>
              <div style={iconBox}><MapPin size={20} color="#e67e22" /></div>
              <div>
                <h4 style={{ margin: 0, fontSize: '1rem' }}>{l.nombre}</h4>
                <p style={subText}>{l.direccion} • {l.zona}</p>
              </div>
            </div>
            <button onClick={() => seleccionarLocal(l)} style={btnSel}>Gestionar</button>
          </div>
        ))}
      </div>
    </div>
  );
};

const formStyle = { background: 'white', padding: '30px', borderRadius: '24px', border: '1px solid #e2e8f0', marginTop: '25px', boxShadow: '0 4px 10px rgba(0,0,0,0.03)' };
const gridForm = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' };
const inputGroup = { display: 'flex', flexDirection: 'column', gap: '8px' };
const labelStyle = { fontSize: '0.75rem', fontWeight: 'bold', color: '#64748b' };
const inputStyle = { padding: '12px', borderRadius: '12px', border: '1px solid #cbd5e1', outline: 'none' };
const btnCrear = { width: '100%', marginTop: '20px', padding: '16px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '14px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', justifyContent: 'center', gap: '10px' };
const listaLocales = { display: 'flex', flexDirection: 'column', gap: '12px', marginTop: '30px' };
const cardLocal = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '18px', background: 'white', borderRadius: '18px', border: '1px solid #e2e8f0' };
const iconBox = { padding: '10px', background: '#fff3e0', borderRadius: '12px' };
const subText = { fontSize: '0.85rem', color: '#94a3b8', margin: '4px 0 0 0' };
const btnSel = { padding: '8px 16px', background: '#f8fafc', color: '#1e293b', border: '1px solid #e2e8f0', borderRadius: '10px', fontWeight: '700', cursor: 'pointer' };

export default GestionLocales;
